class BatteryWatcher {
  static const _channel = EventChannel('com.example/battery_state');

  // Broadcast stream — multiple listeners share one native subscription
  static Stream<int> percent() => _channel
      .receiveBroadcastStream()
      .map((e) => e as int)
      .handleError((e, _) {
        // PlatformException from native side
        debugPrint('battery channel: $e');
      });
}

// Subscribe with cleanup
final sub = BatteryWatcher.percent().listen((p) => setState(() => _pct = p));
@override
void dispose() { sub.cancel(); super.dispose(); } // → triggers onCancel native side

