// ── Dart — typed handling with PlatformException ────
class CameraService {
  static const _ch = MethodChannel('com.example/camera');

  static Future<String> takePicture() async {
    try {
      return await _ch.invokeMethod<String>('takePicture').timeout(
        const Duration(seconds: 15),
      ) ?? '';
    } on PlatformException catch (e) {
      switch (e.code) {
        case 'PERMISSION_DENIED':
          throw const CameraDeniedException();
        case 'NO_CAMERA':
          throw const NoCameraException();
        default:
          rethrow;
      }
    } on MissingPluginException {
      // Running on an unsupported platform (web, desktop) — degrade gracefully
      throw const CameraNotSupportedException();
    } on TimeoutException {
      throw const CameraStuckException();
    }
  }
}

